582→      syslog(`Waiting ${delaySec}s before next iteration...`);
583→      await Bun.sleep(CONFIG.delayBetweenIterations);
584→    }
585→  }
586→
587→  println();
588→  println('==========================================', 'red');
589→  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
590→  syslog('Loop stopped — tasks may still be pending', 'red');
591→  println('==========================================', 'red');
592→  logBuffer.dispose();
593→  process.exit(1);
594→}
